// Simple Data Cleaning Code for N8N
// Extracts and formats organization data without filtering

const inputData = $input.all();

function cleanData(items) {
  return items.map(item => {
    // Handle different data structures
    const org = item.organization || item.json?.organization || item;

    // Skip if no organization data found
    if (!org) {
      console.log('No organization data found for item');
      return null;
    }

    return {
      organization_name: org.name || 'N/A',
      organization_id: org.id || 'N/A',
      domain: org.primary_domain || 'N/A',
      website: org.website_url || 'N/A',
      industry: org.industry || 'N/A',
      employee_size: org.estimated_num_employees || 0,
      location: `${org.city || 'N/A'}, ${org.state || 'N/A'}, ${org.country || 'N/A'}`,
      revenue: org.annual_revenue_printed || org.organization_revenue_printed || 'N/A',
      founded_year: org.founded_year || 'N/A',
      keywords_sample: (org.keywords || []).slice(0, 5).join(', ') || 'N/A'
    };
  }).filter(item => item !== null); // Remove any null entries
}

try {
  // Clean and format the data
  const cleanedData = cleanData(inputData);

  // Log results
  console.log(`Input records: ${inputData.length}`);
  console.log(`Cleaned records: ${cleanedData.length}`);

  // Return cleaned data in n8n format
  return cleanedData.map(company => ({ json: company }));

} catch (error) {
  console.error('Error cleaning data:', error);
  console.error('Error details:', error.message);
  throw error;
}

// n8n Code Node to extract specific fields from people data
const cleanedData = [];

// Process each item from the input
for (const inputItem of $input.all()) {
  const peopleData = inputItem.json.people;

  // Check if people data exists and is a string (JSON)
  if (peopleData && typeof peopleData === 'string') {
    try {
      const parsedPeople = JSON.parse(peopleData);

      // Process each person in the array
      parsedPeople.forEach(person => {
        // Extract only the specified fields
        const cleanedPerson = {
          id: person.id || null,
          name: person.name || null,
          first_name: person.first_name || null,
          last_name: person.last_name || null,
          title: person.title || null,
          linkedin_url: person.linkedin_url || null,
          company_name: person.organization?.name || null,
          company_linkedin: person.organization?.linkedin_url || null,
          company_website: person.organization?.website_url || null
        };

        cleanedData.push(cleanedPerson);
      });

    } catch (error) {
      console.error('Error parsing people data:', error);
    }
  }
}

// Return the cleaned data
return cleanedData.map(person => ({ json: person }));

// For each input item, check if Tittle contains "Marketing"
const filteredItems = items.filter(item => {
  const title = item.json.title || '';
  return title.toLowerCase().includes('marketing');
});

return filteredItems;

const COMPANY_LIMIT = 3;
const EXCEPTION_COUNT = 4;

const allPeople = $items().map(item => item.json);

const peopleByCompany = allPeople.reduce((acc, person) => {
  const company = person.company_name;
  if (!acc[company]) acc[company] = [];
  acc[company].push(person);
  return acc;
}, {});

const finalPeopleList = Object.values(peopleByCompany).flatMap(members => {
  // If there are exactly 4 people, include all of them
  if (members.length === EXCEPTION_COUNT) {
    return members;
  }
  // Otherwise, apply the normal limit
  return members.slice(0, COMPANY_LIMIT);
});

return finalPeopleList.map(person => ({ json: person }));

// Extract all company names
const companyNames = items.map(item => item.json.company_name);

// Get unique company names using Set
const uniqueCompanies = [...new Set(companyNames)];

// Count of unique companies
const uniqueCount = uniqueCompanies.length;

// Return the result
return [{
  json: {
    unique_company_count: uniqueCount,
    unique_companies: uniqueCompanies,
    total_records: items.length
  }
}];

const items = $input.all();
const itemCount = items.length;

return [{ json: { itemCount }, pairedItem: items.map((_, index) => index) }];

// Retrieve all organizations from previous node
const organizations = $input.all();

// Base URL template without organizationIds[]
const baseUrl = "https://app.apollo.io/#/people?personSeniorities[]=vp&personSeniorities[]=director&personSeniorities[]=head&prospectedByCurrentTeam[]=no&sortByField=%5Bnone%5D&sortAscending=false&personDepartmentOrSubdepartments[]=master_marketing";

// Build the organizationIds[] part dynamically
const orgParam = organizations
  .map(item => `organizationIds[]=${item.json.organization_id}`)
  .join("&");

// Construct full URL with all IDs
const url = `${baseUrl}&${orgParam}`;

// Output one item with the combined URL
return [
  {
    json: {
      input: { url },
      include_email: true
    }
  }
];

const items = $input.all();
const updatedItems = items.map((item) => {
  let website = item?.json?.company_website || "";
  // Remove protocol (http, https)
  website = website.replace(/^https?:\/\//, "");
  // Remove "www."
  website = website.replace(/^www\./, "");
  // Extract hostname up to first slash or end of string
  website = website.split("/")[0];
  item.json.company_website = website;
  return item;
});
return updatedItems;
